INSERT INTO offmarket.business_scores (business_id,score_run_id,layer1_base_rate,layer1_comment,layer2_sellability,layer2_comment,layer3_behavioral_trigger,layer3_comment,layer4_market_pull,layer4_comment,final_score,final_tier,final_comment,value_add_thesis,confidence,data_completeness)
VALUES
  ('d6bfad07-7b53-4fd6-911b-ef318a6044ae','642021e3-dffd-4d34-813d-15d18f2a88c1',95.0,'Bert Blair ~73 (Texas Tech ''75 grad), 45-yr tenure. Squarely in 68+ band, max tenure modifier applies.',80.0,'45-year operator with commercial contract base (schools, churches, athletic fields, original Roger Staubach merger). Solid sellability though crew count unverified.',78.0,'4 tells: no LMN/Aspire/Jobber, no team page (404), template testimonials, contact form only. Coasting signal abundant.',88.0,'Plano (DFW commercial-growth corridor) — hottest landscaping consolidator market in TX.',85.0,'A_acquire_self','PRIME A-tier: owner age 73 + 45-yr tenure + commercial-institutional book + abundant coasting tells + DFW market pull. Deep dive pending: successor verification, crew count, contract base verification.','Acquire long-tenure Bert Blair commercial book (schools/churches/athletic). Modernize tech stack (LMN/Aspire), add online quoting, expand DFW commercial footprint. Founder ready for clean exit, no visible successor.','medium',0.7),
  ('6bb8ac88-9d12-42cb-9752-2dc0486ee0cc','642021e3-dffd-4d34-813d-15d18f2a88c1',70.0,'37-yr tenure + WBE/DBE/HUB cert implies likely 60+ owner, but identity opaque. Tenure modifier +5 caps high middle-band.',72.0,'200+ employees, multi-vertical commercial (HOA/parks/govt/education/retail/hospitals). Strong sellability but possibly above SBA micro-acquisition target size.',68.0,'5 tells: opaque ownership, no team page, no LMN/Aspire, phone+form only, no leadership bios at 200+ employee scale.',82.0,'Cypress/Houston metro — strong commercial landscaping consolidator market.',73.0,'B_forward','B-tier: strong tenure + commercial book + coasting tells, but owner identity unverified and 200+ employee size pushes above typical SBA micro-acquisition profile. Cap B due to missing successor verification + low data confidence.','Forward to ETA buyers with $5-15M check size for institutional commercial / municipal book. WBE/DBE certifications create competitive moat. Strong Houston metro footprint.','low',0.55),
  ('b19d89b9-75dd-4114-89bc-8faab78986f1','642021e3-dffd-4d34-813d-15d18f2a88c1',70.0,'2nd-gen brothers ~60-64, 39-yr tenure with +5 tenure modifier. Mid-upper band but not yet exit-age trigger.',85.0,'500+ employees, 6 locations across 5 cities, NALP-recognized = highly sellable but well above SBA micro-acquisition target.',25.0,'Anti-coasting signals: NALP Level Up profile, active growth posture, 2nd-gen brothers actively scaling. Only 1 weak tell (diffuse cap table).',75.0,'San Antonio metro — solid commercial market but not as hot as DFW/Austin.',60.0,'B_forward','B-tier: large institutional commercial player but actively scaling, not coasting. Too large for typical SBA-financed solo acquisition; forward to PE rollup buyers.','Forward to PE landscape rollup platforms (BrightView, Yellowstone, Juniper, LandCare, Park West) as add-on acquisition candidate. 500 employees + 6 locations = bolt-on prize.','medium',0.85),
  ('ae829259-cf4d-4ff2-9af5-b45ae8736123','642021e3-dffd-4d34-813d-15d18f2a88c1',65.0,'34-yr tenure but owner identity opaque — likely 55-65 age range, tenure modifier +5.',60.0,'Family-owned, 15+ DFW municipalities served, commercial+HOA mix. No verified crew count.',68.0,'6 tells: no owner name, no TNLA, no license #, no portal, no LMN/Aspire, no employee count.',88.0,'Fort Worth/DFW commercial-growth — hottest landscaping consolidator market.',70.0,'B_forward','B-tier: DFW commercial book + tenure + coasting tells, but owner identity + age unverified. Cap B due to missing successor verification + low confidence.','Need Comptroller + LinkedIn dig to confirm owner age 60+. If confirmed, forward to ETA buyers for DFW municipal/commercial maintenance book.','low',0.5),
  ('0c6da97e-54b2-4075-9b5f-8478249aa2ca','642021e3-dffd-4d34-813d-15d18f2a88c1',72.0,'Co-owners ~60, 29-yr tenure. Mid-upper band, tenure modifier +3-5.',75.0,'Two co-owners (partnership), HOA/multi-family commercial book, FEMA-certified disaster work = recurring revenue. 4-city operation = sellable infrastructure.',72.0,'5 tells: 4-city operational complexity for aging owners, no LMN/Aspire/Jobber, no full portal, no specific license numbers, no successor visible.',82.0,'Houston HQ + Dallas/Austin/SA presence = strong commercial markets.',74.0,'B_forward','B-tier: woman-owned, 29-yr tenure partnership with HOA/multi-family + FEMA storm recurring revenue. Two co-owners often exit together = motivated seller. Cap B due to medium-low confidence on age verification.','Partnership exit = motivated seller. Forward to ETA / search funds — strong HOA book, FEMA-certified disaster revenue add. Multi-city footprint enables Texas-wide rollup story.','medium',0.75),
  ('b31b8c08-3aa6-497e-b1f7-82aad2302e1e','642021e3-dffd-4d34-813d-15d18f2a88c1',35.0,'22-yr tenure but owner age unverified, likely 40s-50s. Mid-lower band.',45.0,'Multi-trade (lawn+fencing+pressure washing) = pre-specialization small-shop pattern. Limited sellability.',50.0,'4 tells: opaque ownership, no TNLA, no license #, no LMN/Aspire, multi-trade dilution.',80.0,'Houston metro commercial growth.',52.0,'C_watch','C-watch: mixed-trade small-shop owner-operator, owner likely still growth-mode. Owner identity surfaced but age missing.','Watch list — too young + too small for current ETA acquisition pass.','low',0.55),
  ('42bc708c-8673-4db5-80c7-78bb5855eec9','642021e3-dffd-4d34-813d-15d18f2a88c1',88.0,'Jim Curtice ~67 (UH grad, licensed horticulturist), 39-yr tenure. Top of 63-67 band with +5 tenure modifier.',78.0,'Solo founder-operator 39 years, premium River Oaks/Bellaire/Memorial commercial+upscale residential book. Strong sellability for niche acquirer.',80.0,'6 tells: empty testimonial template placeholder still on live site, no LMN/Aspire/Jobber, no employee count, no portal, premium niche refusing to commoditize = textbook owner-coasting pattern.',82.0,'Houston Harris County premium commercial corridor.',81.0,'A_acquire_self','PRIME A-tier: Jim Curtice 67 + 39-yr solo tenure + premium commercial book + textbook coasting signals (empty testimonial placeholder STILL on live site is the smoking gun). Deep dive pending: contract base verification, crew count, succession plan.','Acquire single-owner premium Houston commercial book. Modernize tech (LMN/Aspire), add online quoting, retain founder 6-12 months for client handoff. River Oaks/Bellaire/Memorial book has high retention.','medium',0.75),
  ('cb751d1b-6b3c-4c18-b3b2-f71dae9fbdb3','642021e3-dffd-4d34-813d-15d18f2a88c1',20.0,'9 yrs tenure, father-son active duo. Hard gate: <5 yrs would force ≤35, this just above but still penalty for sub-decade tenure.',30.0,'Father-son active duo, residential-leaning testimonials, no commercial validation. Early-growth stage.',25.0,'Anti-coasting: family dynasty actively forming, son just stepping into President role. 0-1 weak tells.',88.0,'Austin Travis Co. — top market.',34.0,'D_pass','D-pass: only 9 yrs tenure, father-son growth-mode dynasty. Far too early in lifecycle for ETA buyout.','Pass — pre-succession family dynasty. Revisit in 10-15 years.','medium',0.6),
  ('26056a29-d236-4db4-aea0-bd2f7fc14fe3','642021e3-dffd-4d34-813d-15d18f2a88c1',70.0,'Marc Moreno ~60, 23-yr tenure (entity 43 yrs but Moreno only since 2003 partnership). Mid-upper band.',65.0,'TNLA Certified Landscape Professionals + husband-wife team + commercial/residential mix. Solid sellability.',70.0,'5 tells: husband-wife principal team (pre-exit pattern), no visible tech stack, exit story openly told on about page, no children mentioned, TNLA only credential.',75.0,'San Antonio Bexar Co. commercial.',70.0,'B_forward','B-tier: husband-wife operator team, owner ~60, 23-yr tenure post-first-succession, no children in business = likely clean sale. TNLA-credentialed. Cap B due to medium confidence on age.','Forward to ETA buyers. Already through one succession event (John Hill → Marc Moreno 2013) = clean transition history. Husband-wife exit = motivated.','medium',0.8),
  ('513275da-df11-4c9d-98bc-2ea877c9f813','642021e3-dffd-4d34-813d-15d18f2a88c1',30.0,'Years in business unverified, owner age unknown. Default low-band.',35.0,'Owner-operator pattern (Oscar does work himself per testimonials) = 1-crew sub-target size.',50.0,'TCEQ license but no TNLA, no LMN/Aspire, no portal, no full owner name. 5 tells but cannot verify if coasting or just small.',75.0,'San Antonio commercial market.',45.0,'C_watch','C-watch: cannot verify tenure or owner age. Owner-operator pattern signals sub-target size. Hard gate triggered: ''cannot verify'' borderline drop, kept at C floor.','Watch — verify owner identity + years in business via Comptroller. If 20+ years confirmed, escalate.','low',0.4),
  ('ceef8a29-34ba-439a-aaff-124dee5d10c8','642021e3-dffd-4d34-813d-15d18f2a88c1',22.0,'Owner ~45, 12-yr tenure. Far below succession-eligible age band.',55.0,'12-yr tenure (just at lower bound), HOA/commercial testimonials confirm recurring revenue.',35.0,'Owner in growth phase. 1-2 weak tells only.',75.0,'San Antonio commercial.',43.0,'D_pass','D-pass: owner too young (~45) for succession exit. Growth-mode operator.','Pass — revisit in 10-15 years.','medium',0.65),
  ('2d81a17f-5506-4fff-9c54-9eea20981183','642021e3-dffd-4d34-813d-15d18f2a88c1',65.0,'Javier ~60, 26-yr tenure with +3 modifier. Mid-upper band but uncertainty pulls down.',30.0,'Tiny-shop signals: Gmail email, no commercial testimonials, no licenses. Sub-target size. Son already in succession.',50.0,'7 tells: residential-only testimonials, Gmail address, no LMN/Aspire, no licenses disclosed, owner-operator + son small shop.',75.0,'San Antonio commercial.',54.0,'C_watch','C-watch: mid-succession father+son small shop. Family-owned with son in business = exit goes to son, not market.','Watch — likely intra-family handoff, not acquisition target.','medium',0.6),
  ('aaae21e5-6f05-4508-8fde-482c664f5757','642021e3-dffd-4d34-813d-15d18f2a88c1',72.0,'Matt Brady ~58, 32-yr tenure with +5 modifier. Top of 58-62 band.',62.0,'5,128 ''neighbors'' = residential-heavy book, M-F only hours. Less commercial-recurring than peers.',55.0,'5 tells: 2012-era tech adoption now stale (dated client portal, no LMN/Aspire), residential lean, M-F only schedule, no online quote, no successor visible.',88.0,'Plano DFW — hottest market.',67.0,'B_forward','B-tier: solid 32-yr founder still active at 58, DFW market, but residential-heavy book hurts commercial-landscape thesis. Cap B due to lower commercial mix.','Forward to ETA buyers with residential+commercial appetite. DFW market + 32-yr brand + 5,000+ customer book.','medium',0.7),
  ('3e91d8b5-bf5d-4995-8fde-f7b5301512d4','642021e3-dffd-4d34-813d-15d18f2a88c1',35.0,'Bill Kennedy ~50, 26-yr tenure with +5 modifier. Bottom of 53-57 band given age 50.',60.0,'Multi-state (TX+OK), TNLA+TCEQ licensed, eponymous brand. Owner divided attention as practicing attorney.',55.0,'5 tells: dual-career attorney since 2007 (divided attention IS the coasting tell), no LMN/Aspire, eponymous brand bound to owner identity, EPA branding only, cross-state stretch.',88.0,'Frisco DFW.',55.0,'C_watch','C-watch: unique coasting profile — attorney as primary career means landscape business runs on autopilot. But age 50 too young for typical exit. Hard gate: confidence-low and would land C-tier naturally.','Watch — owner''s divided focus could create opportunistic acquisition window if right offer materializes despite young age.','medium',0.75),
  ('07963722-0f1a-491b-be03-ef3e1c8c40ef','642021e3-dffd-4d34-813d-15d18f2a88c1',35.0,'Current owners ~50, only 9-yr tenure post-2017 succession. Despite entity 27 yrs, the relevant operator window is short.',70.0,'50+ employees, 5000+ clients, multiple TDA licenses, TNLA — strong sellability.',25.0,'Anti-coasting: actively modernizing tech (online quote + payment portal). Current owners investing, not coasting. 0-1 tells.',88.0,'Lewisville DFW commercial growth.',52.0,'C_watch','C-watch: already through one succession event 2017, current owners 9-yr tenure and modernizing actively. 3-5 yr horizon target, not near-term.','Watch list — revisit in 3-5 years when Jack & Ann reach 55+.','medium',0.85),
